package com.pos;
import javax.swing.*;import java.awt.*;import java.sql.*;
public class UserProfilePanel extends JPanel {private final UserSession s;private final JTextField name=new JTextField(20),email=new JTextField(20),phone=new JTextField(15),address=new JTextField(24),code=new JTextField(14),loyalty=new JTextField(15),newpass=new JTextField(16); public UserProfilePanel(UserSession s){super(new GridBagLayout());this.s=s;GridBagConstraints g=new GridBagConstraints();g.insets=new Insets(5,5,5,5);g.fill=GridBagConstraints.HORIZONTAL;String[] labels={"Full Name","Email","Phone","Address","Customer Code","Loyalty Number","New Password"};JTextField[] fs={name,email,phone,address,code,loyalty,newpass};for(int i=0;i<labels.length;i++){g.gridx=0;g.gridy=i;add(new JLabel(labels[i]),g);g.gridx=1;add(fs[i],g);}code.setEditable(false);loyalty.setEditable(false);JButton save=new JButton("Update Profile"),pass=new JButton("Change Password");g.gridx=0;g.gridy=labels.length;add(save,g);g.gridx=1;add(pass,g);save.addActionListener(e->save());pass.addActionListener(e->password());load();}
 private void load(){try(Connection c=DB.getConnection();PreparedStatement p=c.prepareStatement("SELECT u.full_name,u.email,u.phone,u.address,cp.customer_code,cp.loyalty_number FROM users u JOIN customer_profiles cp ON cp.user_id=u.user_id WHERE u.user_id=?")){p.setInt(1,s.userId);ResultSet r=p.executeQuery();if(r.next()){name.setText(r.getString(1));email.setText(r.getString(2));phone.setText(r.getString(3));address.setText(r.getString(4));code.setText(r.getString(5));loyalty.setText(r.getString(6));}}catch(Exception e){UIUtils.error(this,e);}}
 private void save(){try(Connection c=DB.getConnection();PreparedStatement p=c.prepareStatement("UPDATE users SET full_name=?,email=?,phone=?,address=? WHERE user_id=?")){p.setString(1,name.getText());p.setString(2,email.getText());p.setString(3,phone.getText());p.setString(4,address.getText());p.setInt(5,s.userId);p.executeUpdate();Audit.log(s,"UPDATE_PROFILE","Customer profile edited");UIUtils.info(this,"Profile updated.");}catch(Exception e){UIUtils.error(this,e);}}
 private void password(){if(newpass.getText().length()<6){UIUtils.info(this,"Password must contain at least 6 characters.");return;}try(Connection c=DB.getConnection();PreparedStatement p=c.prepareStatement("UPDATE users SET password_hash=? WHERE user_id=?")){p.setString(1,PasswordUtil.hash(newpass.getText()));p.setInt(2,s.userId);p.executeUpdate();newpass.setText("");Audit.log(s,"CHANGE_PASSWORD","Password changed");UIUtils.info(this,"Password changed.");}catch(Exception e){UIUtils.error(this,e);}}
}
